# 内存初始化
def init_memory(size):
    memory = []
    for i in range(size):
        memory.append(0)
    return memory


# 基本分页的分配过程
def allocate(memory, job_id, job_size):
    for i in range(len(memory) - job_size + 1):
        if all(val == 0 for val in memory[i:i+job_size]):
            for j in range(i, i+job_size):
                memory[j] = job_id
            return True
    return False


# 作业空间的回收
def deallocate(memory, job_id):
    for i in range(len(memory)):
        if memory[i] == job_id:
            memory[i] = 0


# 分区的显示
def display_memory(memory):
    print(memory)


# 测试
if __name__ == '__main__':
    # 初始化内存
    memory = init_memory(10)
